Q2. Sliding window using Deque(LinkedList in java) - O(n)
```
    private static void offerLast(LinkedList<Integer> list, int a) {
        while (!list.isEmpty() && list.peekLast() > a ) {
            list.pollLast();
        }
        list.addLast(a);
    }
    public static int solve(int[] a, int m) {
        LinkedList<Integer> list = new LinkedList<>();
        int right = 0;
        while (right < m) {
            offerLast(list, a[right]);
            right++;
        }   

        int left = 0;
        int max = list.peek();  

        while(right < a.length) {
           if (a[left] == list.peek()) {
                list.poll();
            }
            left++;            
            offerLast(list, a[right]);
            max = Math.max(max, list.peek());            
            right++;
        }

        return max;
    }

I use a PriorityQueue to save the smallest sums and then iterate over it saving the pairs 
```
public static List<List<Integer>> kSmallestPairs(int[] nums1, int[] nums2, int k) {
        PriorityQueue<int[]> que = new PriorityQueue<>((a,b)->(a[0]-a[1])-(b[0]-b[1]));
        ArrayList<List<Integer>> res = new ArrayList<>();
        if(nums1.length==0 || nums2.length==0 || k==0) 
            return res;

        for(int i=0; i<nums1.length; i++)
            que.offer(new int[]{nums1[i], nums2[0], 0});

        while(!que.isEmpty()){
            int[] cur = que.poll();
            if(Math.abs(cur[0]-cur[1]) < k){
                Integer[] temp = new Integer[] {cur[0], cur[1]};
                List<Integer> tempList = Arrays.asList(temp);
                res.add(tempList);
            }
            if(cur[2] == nums2.length-1) continue;
            que.offer(new int[]{cur[0],nums2[cur[2]+1], cur[2]+1});
        }
        return res;
    }
