public int maxMinInSegments(int[] arrs, int m){
    TreeMap<Integer,Integer> map = new TreeMap<>();
    int i = 0;
    int min = Integer.MIN_VALUE;
    while(i < arrs.length && i < m){
        map.put(arrs[i], map.getOrDefault(arrs[i], 0) + 1);
        i++;
    }
    min = Math.max(min, map.firstKey());

    int j = m;
    while(j < arrs.length) {
        map.put(arrs[i], map.getOrDefault(arrs[i], 0) + 1);
        map.put(arrs[j - m], map.get(arrs[j - m]) - 1);
        if(map.get(arrs[j - m]) == 0){
            map.remove(arrs[j - m]);
        }
        min = Math.max(min, map.firstKey());
        j++;
    }

    return min;
}
